<script setup lang="ts">import type { BpmPolicyType } from '#/api/system/bpm/policy'; import { ElRadioButton, ElRadioGroup } from 'element-plus'; defineProps<{ modelValue: BpmPolicyType; disabled?: boolean }>(); const emit=defineEmits<{ 'update:modelValue':[value:BpmPolicyType] }>(); function change(value:string|number|boolean|undefined){if(typeof value==='string')emit('update:modelValue',value as BpmPolicyType)}</script>
<template><ElRadioGroup :disabled="disabled" :model-value="modelValue" @update:model-value="change"><ElRadioButton value="START_VISIBILITY">发起范围</ElRadioButton><ElRadioButton value="CANDIDATE">审批人</ElRadioButton><ElRadioButton value="APPROVAL">审批方式</ElRadioButton></ElRadioGroup></template>
